// Pull both ensures (`res@ == self@`) into context for r1 and r2 so the two
// ensures-instances line up on the same `self_@` witness.
assert(r1@ == self_@);
assert(r2@ == self_@);

// Transitively, the two views must coincide.
assert(r1@ == r2@);

// Unfold the view equality to the underlying byte sequence and close with
// sequence extensionality, so any per-index check inside
// `det_clone_up_to_view_equal` is discharged.
assert(r1.id@ == self_.id@);
assert(r2.id@ == self_.id@);
assert(r1.id@ =~= r2.id@);
assert(r1.id@ == r2.id@);
